matches = []
for proj in design_projects:
    if proj in funding_lookup:
        amount = funding_lookup[proj]
        if amount > 50000:
            matches.append(proj)
    else:
        # Partial match check
        for fund_name in funding_lookup:
            if proj in fund_name or fund_name in proj:
